      {
        "source": "謝仕榮先生",
        "target": "Mr. Tse Sze-wing",
        "role": "Independent Non-Executive Chairman"
      }
    ],
    "terms": [
      {
        "source": "新業務價值",
        "target": "VONB"
      },
      {
        "source": "2019冠狀病毒病",
        "target": "COVID-19"
      }
